\title{Extraction of \texorpdfstring{Cs-137}{Cs-137} from Nucleonic Level Sensors: Laboratory Procedure}
\author{Radiation Safety and Nuclear Chemistry Laboratory}
\date{Revised: \today}

\begin{document}

\maketitle

\section*{Safety Warning}
\begin{itemize}
    \item \textbf{This procedure must only be performed by trained personnel in a licensed radioactive materials laboratory.}
    \item \textbf{Cs-137 is a high-energy gamma emitter ($E_\gamma = \SI{662}{\kilo\electronvolt}$) and a beta emitter.} Always use appropriate shielding (lead, lead glass) and maintain maximum practical distance.
    \item \textbf{Follow ALARA principles strictly.} Wear a lab coat, safety glasses, double gloves, and a whole-body dosimeter. Use a calibrated survey meter before, during, and after work.
    \item \textbf{The source capsule is typically sealed.} Extraction \textbf{breaches this seal} and creates dispersible contamination. Perform all work in a certified fume hood or glovebox designated for radioactive work.
    \item \textbf{Know your institutional regulations} for handling, waste disposal, and documentation of sealed source breaches.
\end{itemize}

\section{Introduction and Principle}
Nucleonic level sensors (also called nuclear gauges) often use a small, sealed \ch{^{137}Cs} source (activity typically \SIrange{10}{100}{\milli\curie}). Cesium-137 decays to metastable \ch{^{137m}Ba} with a 30-year half-life, emitting the characteristic \SI{662}{\kilo\electronvolt} gamma photon. 

The extraction procedure involves the \textbf{physical opening of the source capsule} and chemical dissolution of the source matrix (often \ch{CsCl} or \ch{Cs2O}) to obtain \ch{Cs+} in aqueous solution for experimental use (e.g., tracer studies, calibration). The chemical principle is the high solubility of cesium salts in water or dilute acid.

\section{Equipment and Materials}
\begin{itemize}
    \item \textbf{Source:} Decommissioned/defective nucleonic level sensor with \ch{^{137}Cs} source capsule.
    \item \textbf{Containment:} Negative-pressure fume hood or glovebox.
    \item \textbf{Shielding:} Lead bricks, lead-glass viewing window.
    \item \textbf{Tools:} Long-handled forceps, remote manipulation tools, small vise, rotary tool with cutting disc (\textbf{for metal capsules}), ceramic mortar and pestle (\textbf{for ceramic capsules}).
    \item \textbf{Glassware:} Beakers (\SI{50}{\milli\liter}), watch glass, stirring rod, filtration setup, volumetric flask.
    \item \textbf{Chemicals:} Deionized water, \SI{1}{\Molar} \ch{HNO3} or \ch{HCl}, ethanol (for cleaning).
    \item \textbf{Safety:} Calibrated gamma survey meter, alpha/beta pancake probe, absorbent paper, plastic-backed bench cover, radioactive waste containers (solid/liquid), personal protective equipment (PPE).
\end{itemize}

\section{Step-by-Step Procedure}

\subsection{Pre-Extraction Setup}
\begin{enumerate}
    \item \textbf{Survey:} Use a gamma survey meter to confirm the presence and location of the source within the sensor housing. Document the exposure rate at \SI{30}{\centi\meter}.
    \item \textbf{Decontaminate} the external housing of the sensor with a damp cloth. Survey again to ensure no loose contamination.
    \item \textbf{Prepare the workspace:} Line the hood with absorbent, plastic-backed paper. Arrange shielding to minimize dose to the torso and eyes. Have all tools and containers within easy reach.
    \item \textbf{Remove the source capsule:} Following the manufacturer's manual, disassemble the sensor housing to access the source capsule. Use long tools. Place the isolated capsule in a secondary containment tray.
\end{enumerate}

\subsection{Capsule Opening and Dissolution}
\textbf{Note:} Capsule type (stainless steel weld-sealed vs. ceramic) dictates the opening method.

\begin{enumerate}
    \item \textbf{For a metal capsule:}
    \begin{enumerate}
        \item Secure the capsule in a small vise \textbf{within the hood}.
        \item Using a rotary tool with a cutting disc (\textit{keep hands behind shielding}), carefully make a shallow groove around the capsule's perimeter. \textbf{Do not cut through completely on the first pass.}
        \item Use a small chisel or pliers to pry open the capsule along the scored line.
    \end{enumerate}
    \item \textbf{For a ceramic capsule:}
    \begin{enumerate}
        \item Wrap the capsule in a Kimwipe and place it in a ceramic mortar.
        \item Gently crush the capsule with the pestle. Apply minimal force to avoid aerosolization.
    \end{enumerate}
    \item \textbf{Transfer the source material:} The active material is usually a white or pale yellow powder or sintered pellet. Carefully pour/tap it into a \SI{50}{\milli\liter} beaker. Rinse any residual powder from the capsule fragments with a minimal amount of deionized water.
    \item \textbf{Dissolution:}
    \begin{enumerate}
        \item Add \SI{10}{\milli\liter} of deionized water to the beaker. If dissolution is incomplete, add \SI{1}{\milli\liter} increments of \SI{1}{\Molar} \ch{HNO3} while stirring with a glass rod. \ch{CsCl} dissolves readily in water; \ch{Cs2O} reacts to form \ch{CsOH}.
        \item Cover with a watch glass and allow to stir gently for \SI{30}{\minute}.
        \item If an insoluble residue remains (e.g., ceramic binder, metal fragments), filter the solution through a fine filter paper into a clean beaker. Rinse the residue with \SI{5}{\milli\liter} of water.
    \end{enumerate}
\end{enumerate}

\subsection{Post-Extraction Processing}
\begin{enumerate}
    \item \textbf{Quantitative Transfer:} Transfer the filtrate to an appropriate volumetric flask (e.g., \SI{25}{\milli\liter}). Dilute to the mark with deionized water. This is your stock \ch{^{137}Cs} solution.
    \item \textbf{Characterization:}
    \begin{enumerate}
        \item Use a gamma spectrometer with a high-purity germanium (HPGe) detector to confirm the radionuclidic purity (check for the \SI{662}{\kilo\electronvolt} photopeak).
        \item Perform liquid scintillation counting or gamma counting to determine the exact activity concentration (in \si{\becquerel\per\milli\liter} or \si{\micro\curie\per\milli\liter}).
    \end{enumerate}
    \item \textbf{Cleanup and Waste:}
    \begin{enumerate}
        \item Place all contaminated tools, capsule fragments, filter paper, and gloves into a \textbf{solid radioactive waste} container.
        \item Decontaminate the work surface. Perform a thorough survey with an alpha/beta probe and gamma meter. Confirm no contamination spread.
        \item Liquid waste (rinsates, unused solution) must be placed in a designated \textbf{liquid radioactive waste} container.
    \end{enumerate}
\end{enumerate}

\section{Data Recording and Compliance}
\begin{itemize}
    \item \textbf{Logbook Entry:} Record source ID, initial exposure rate, final solution volume, measured activity, date, and performer's name.
    \item \textbf{Waste Manifest:} Update the radioactive waste log with the new solid and liquid waste generated.
    \item \textbf{Regulatory Notification:} If required by license, report the intentional breach of a sealed source to the appropriate regulatory body (e.g., NRC, Agreement State).
\end{itemize}

\section{Troubleshooting}
\begin{itemize}
    \item \textbf{Low Dissolution Yield:} The source matrix may be a ceramic or glass. Gentle heating with dilute acid or use of a small amount of HF (\textbf{extreme caution!}) may be required.
    \item \textbf{High Contamination:} If a spill or aerosol release occurs, \textbf{stop work immediately}, contain the area, and notify radiation safety personnel.
    \item \textbf{Unusual Activity:} If gamma spectroscopy shows significant impurities, the source may be old or damaged. Consult with a health physicist.
\end{itemize}

\begin{center}
    \rule{0.8\textwidth}{0.5pt}
\end{center}

\noindent \textbf{Disclaimer:} This document is for instructional purposes. Actual procedures must be developed and approved by the institution's Radiation Safety Officer (RSO) and comply with all applicable federal and state regulations.

\end{document}
